// ══ excel.js — Campo Cuichapa PWA ═══════════════════════════════
// Generación, construcción y descarga de reportes Excel.
// Requiere: config.js (globals), CDN JSZip, CDN XLSX.
// Funciones externas usadas: getHistorial(), showToast() — disponibles como globals.

// ══ GENERAR EXCEL DE REPORTE DE POZOS ══════════════════
function _excelBuildSheet(wb, recorredor, fecha, reportes){
  var fechaDisplay = new Date(fecha+'T12:00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'long',year:'numeric'});
  reportes.sort(function(a,b){ return new Date(a.fecha)-new Date(b.fecha); });
  var rows = [];
  rows.push(['LIFTING DE MÉXICO S.A. DE C.V.']);
  rows.push(['TOMA DE REGISTROS EN POZOS  ·  LIF-PRO-FO-004']);
  rows.push([]);
  rows.push(['RECORREDOR:', recorredor, '', '', '', '', '', 'FECHA:', fechaDisplay]);
  rows.push([]);
  rows.push([
    'NO','POZO','HORA','ESTATUS',
    'FLUYE A: FRAC TANK (FT) / BATERÍA (BSCII)',
    'SISTEMA DE RECUPERACIÓN','DIÁMETRO ESTRANGULADOR',
    'TUBERÍA DE PRODUCCIÓN (TP) kg/cm²',
    'LÍNEA DE DESCARGA (LDD) kg/cm²',
    'TUBERÍA DE REVESTIMIENTO (TR) kg/cm²',
    'EMBOLADAS (EPM)','CARRERA','OBSERVACIONES'
  ]);
  reportes.forEach(function(r,i){
    var hora = (function(d){var h=d.getHours(),m=d.getMinutes();return (h<10?'0':'')+h+':'+(m<10?'0':'')+m;})(new Date(r.fecha));
    var estatus = r.estatus || '';
    if(!estatus && r.msg){ var m=r.msg.match(/Estado[^:]*:[^\r\n]*/i); if(m) estatus=m[0].split(':').pop().trim(); }
    var fluye = r.fluye || '';
    if(!fluye && r.msg){ var m2=r.msg.match(/Fluye:[^\r\n]*/i); if(m2) fluye=m2[0].replace(/Fluye:/i,'').trim(); }
    var sap = r.sap || '';
    if(!sap && r.msg){ var m3=r.msg.match(/SAP:[^\r\n]*/i); if(m3) sap=m3[0].replace(/SAP:/i,'').trim(); }
    rows.push([
      i+1, r.pozo?'C-'+r.pozo:'', hora, estatus, fluye, sap,
      r.estrang||'',
      r.ptp!=null?r.ptp:'', r.ldd!=null?r.ldd:'', r.ptr!=null?r.ptr:'',
      r.epm!=null?r.epm:'', r.carrera!=null?r.carrera:'', r.obs||''
    ]);
  });
  rows.push([]);
  rows.push(['','','','','','','','','','','','','1 BN: Bombeo Neumático | BM: Bombeo Mecánico | FY: Fluyente']);

  var ws = XLSX.utils.aoa_to_sheet(rows);
  ws['!cols'] = [{wch:4},{wch:10},{wch:8},{wch:14},{wch:22},{wch:18},{wch:16},
                 {wch:14},{wch:14},{wch:14},{wch:12},{wch:10},{wch:35}];

  // Style title rows
  var cols13 = ['A','B','C','D','E','F','G','H','I','J','K','L','M'];
  cols13.forEach(function(col){
    // Header row (row 6)
    var ch = ws[col+'6'];
    if(ch){ ch.s = {font:{bold:true,color:{rgb:'FFFFFF'}},fill:{fgColor:{rgb:'1E4A80'}},alignment:{horizontal:'center',wrapText:true}}; }
    // Title row 1
    var ct = ws[col+'1'];
    if(ct && col==='A'){ ct.s = {font:{bold:true,size:13,color:{rgb:'1E4A80'}}}; }
  });

  // Sheet name: "Manrique 04-Jun"
  var mes = new Date(fecha+'T12:00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'short'}).replace('.','');
  var sheetName = (recorredor.split(' ')[0]+' '+mes).slice(0,31);
  // Avoid duplicates
  var n = 2;
  var orig = sheetName;
  while(wb.SheetNames.indexOf(sheetName) !== -1){ sheetName = (orig+'('+n+')').slice(0,31); n++; }
  XLSX.utils.book_append_sheet(wb, ws, sheetName);
}

function descargarExcelReporte(){
  if(typeof XLSX === 'undefined'){ showToast('⚠️ Cargando librería Excel, intenta de nuevo'); return; }

  var hist = getHistorial().filter(function(r){ return !r.esAlarma; });
  if(!hist.length){ showToast('⚠️ Sin reportes en el historial'); return; }

  // Group by date then by recorredor
  var porFecha = {};
  hist.forEach(function(r){
    var d = new Date(r.fecha).toISOString().slice(0,10);
    if(!porFecha[d]) porFecha[d] = {};
    var rec = r.recorredor || 'Sin asignar';
    if(!porFecha[d][rec]) porFecha[d][rec] = [];
    porFecha[d][rec].push(r);
  });

  var wb = XLSX.utils.book_new();

  // Sort dates ascending — oldest first, newest last
  var fechas = Object.keys(porFecha).sort();
  fechas.forEach(function(fecha){
    var recs = porFecha[fecha];
    // Sort recorredores: Manrique, Cirilo, Juan Carlos, then others
    var orden = ['Manrique','Cirilo','Juan Carlos','Jose','Luis'];
    var recList = Object.keys(recs);
    recList.sort(function(a,b){
      var ia = orden.indexOf(a), ib = orden.indexOf(b);
      if(ia===-1) ia=99; if(ib===-1) ib=99;
      return ia-ib;
    });
    recList.forEach(function(rec){
      _excelBuildSheet(wb, rec, fecha, recs[rec]);
    });
  });

  var mesAnio = new Date().toLocaleDateString('es-MX',{month:'short',year:'numeric'}).replace(' ','_').replace('.','');
  var nombre = 'Reporte_Pozos_'+mesAnio+'.xlsx';
  XLSX.writeFile(wb, nombre);
  showToast('📥 '+wb.SheetNames.length+' hojas · '+nombre);
}

function descargarExcelRecorredor(recKey){
  if(typeof XLSX === 'undefined'){ showToast('⚠️ Cargando librería Excel, intenta de nuevo'); return; }

  // Determine which recorredor to filter
  var nombreFiltro = null;
  if(recKey){
    // Called from supervision with a key
    var recObj = SUP_RECORREDORES.find(function(r){ return r.key === recKey; });
    nombreFiltro = recObj ? recObj.nombre : recKey;
  } else {
    // Called from recorredor's own profile
    nombreFiltro = typeof REC !== 'undefined' ? REC : null;
  }
  if(!nombreFiltro){ showToast('⚠️ No se pudo identificar el recorredor'); return; }

  var hist = getHistorial().filter(function(r){
    return !r.esAlarma && r.recorredor === nombreFiltro;
  });
  if(!hist.length){ showToast('⚠️ Sin reportes de '+nombreFiltro); return; }

  // Group by date
  var porFecha = {};
  hist.forEach(function(r){
    var d = new Date(r.fecha).toISOString().slice(0,10);
    if(!porFecha[d]) porFecha[d] = [];
    porFecha[d].push(r);
  });

  var wb = XLSX.utils.book_new();
  var fechas = Object.keys(porFecha).sort(); // oldest first
  fechas.forEach(function(fecha){
    _excelBuildSheet(wb, nombreFiltro, fecha, porFecha[fecha]);
  });

  var safe = nombreFiltro.replace(/\s+/g,'_');
  var nombre = 'Reporte_'+safe+'_'+new Date().toISOString().slice(0,10)+'.xlsx';
  XLSX.writeFile(wb, nombre);
  showToast('📥 '+wb.SheetNames.length+' días · '+nombre);
}


// ═══ EXCEL NUEVO FORMATO ═══════════════════════════════════════════════
var _EXCEL_TPL_B64 = '';

function _b64ToUint8(b64){
  var bin=atob(b64),arr=new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
  return arr;
}

function _xlFillCell(xml,addr,val,isNum){
  var v=String(val===null||val===undefined?'':val).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  var r1=new RegExp('<c r="'+addr+'"([^/]*)/>');
  var m=xml.match(r1);
  if(m){
    var a=m[1].replace(/\s*t="[^"]*"/g,'');
    return xml.replace(m[0], isNum?'<c r="'+addr+'"'+a+'><v>'+v+'</v></c>':'<c r="'+addr+'"'+a+' t="inlineStr"><is><t>'+v+'</t></is></c>');
  }
  var r2=new RegExp('<c r="'+addr+'"([^>]*)>[\\s\\S]*?</c>');
  m=xml.match(r2);
  if(m){
    var a=m[1].replace(/\s*t="[^"]*"/g,'');
    return xml.replace(m[0], isNum?'<c r="'+addr+'"'+a+'><v>'+v+'</v></c>':'<c r="'+addr+'"'+a+' t="inlineStr"><is><t>'+v+'</t></is></c>');
  }
  return xml;
}

function _xlWipe(xml,addr){
  var r2=new RegExp('<c r="'+addr+'"([^>]*)>[\\s\\S]*?</c>');
  var m=xml.match(r2);
  if(m){var a=m[1].replace(/\s*t="[^"]*"/g,'');return xml.replace(m[0],'<c r="'+addr+'"'+a+' t="n"></c>');}
  var r1=new RegExp('<c r="'+addr+'"([^/]*)/>');
  m=xml.match(r1);
  if(m){var a=m[1].replace(/\s*t="[^"]*"/g,'');return xml.replace(m[0],'<c r="'+addr+'"'+a+' t="n"></c>');}
  return xml;
}

function _xlDesc(xml,addr,val){
  var v=String(val||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  var r2=new RegExp('<c r="'+addr+'"([^>]*)>[\\s\\S]*?</c>');
  var m=xml.match(r2);
  var rep='<c r="'+addr+'" s="18" t="inlineStr"><is><t>'+v+'</t></is></c>';
  if(m) return xml.replace(m[0],rep);
  var r1=new RegExp('<c r="'+addr+'"([^/]*)/>');
  m=xml.match(r1);
  if(m) return xml.replace(m[0],rep);
  return xml;
}

function _buildSheet(tplXml,rec,fecha,reps){
  var xml = tplXml;

  // ── Encabezado ─────────────────────────────────
  xml = _xlFillCell(xml, 'C4', rec,   false);   // Nombre recorredor
  xml = _xlFillCell(xml, 'M4', fecha, false);   // Fecha
  xml = _xlWipe(xml, 'H4');                      // Borrar supervisor

  // ── Clasificar reportes ─────────────────────────
  var pozos = [], ft1 = [], ft2 = [];
  reps.forEach(function(r) {
    var modo = r.modo || 'pozo';
    if (modo === 'guardia') {
      ft1.push(r);                               // Niveles de Guardia → TURNO 1
    } else {
      pozos.push(r);
      if (r.ctm != null && r.fluye === 'FT') ft2.push(r); // FT con nivel → TURNO 2
    }
  });
  function byT(a,b){ return new Date(a.fecha) - new Date(b.fecha); }
  pozos.sort(byT); ft1.sort(byT); ft2.sort(byT);

  // ── Filas de pozos (rows 8-25, max 18) ─────────
  for (var i = 0; i < 18; i++) {
    var row = 8 + i;
    var r   = pozos[i] || null;
    var cols = 'BCDEFGHIJKLM'.split('');

    if (!r) {
      cols.forEach(function(c){ xml = _xlWipe(xml, c + row); });
      continue;
    }

    var d    = new Date(r.fecha);
    var hora = (d.getHours()<10?'0':'')+d.getHours()+':'+(d.getMinutes()<10?'0':'')+d.getMinutes();
    var modo = r.modo || 'pozo';

    if (modo === 'cabezal' || modo === 'estacion' || modo === 'nota') {
      // Fila especial — hora en C, descripción en D, resto vacío
      var tipo = modo === 'cabezal' ? 'CAB' : modo === 'estacion' ? 'ESTACION' : 'NOTA';
      var obs  = r.obs || '';
      if (!obs && r.msg) {
        obs = r.msg.split('\n')
          .filter(function(l){ return l.trim() && !/^[📍🕐👷📊]/.test(l); })
          .slice(0, 2).join(' | ').substring(0, 150);
      }
      xml = _xlWipe(xml, 'B' + row);
      xml = _xlFillCell(xml, 'C' + row, hora, false);
      xml = _xlDesc(xml,    'D' + row, tipo + ' — ' + obs);
      'EFGHIJKLM'.split('').forEach(function(c){ xml = _xlWipe(xml, c + row); });

    } else {
      // Reporte diario normal
      var pozo   = r.pozo ? 'C-' + r.pozo : '';
      var est    = r.estatus || '';
      var fluye  = r.fluye  || '';
      var sap    = r.sap    || '';
      if (!est && r.msg) {
        var em = r.msg.match(/Estado[^:]*:\s*([^\n]+)/i);
        if (em) est = em[1].trim().substring(0, 20);
      }
      if (!sap && r.msg) {
        var sm = r.msg.match(/SAP:\s*([A-Z]{2,3})/i);
        if (sm) sap = sm[1];
      }
      xml = _xlFillCell(xml, 'B' + row, pozo,   false);
      xml = _xlFillCell(xml, 'C' + row, hora,   false);
      xml = _xlFillCell(xml, 'D' + row, est,    false);
      xml = _xlFillCell(xml, 'E' + row, fluye,  false);
      xml = _xlFillCell(xml, 'F' + row, sap,    false);
      xml = _xlFillCell(xml, 'G' + row, r.estrang || '', false);
      if (r.ptp     != null) xml = _xlFillCell(xml, 'H' + row, r.ptp,     true);  else xml = _xlWipe(xml, 'H' + row);
      if (r.ldd     != null) xml = _xlFillCell(xml, 'I' + row, r.ldd,     true);  else xml = _xlWipe(xml, 'I' + row);
      if (r.ptr     != null) xml = _xlFillCell(xml, 'J' + row, r.ptr,     true);  else xml = _xlWipe(xml, 'J' + row);
      if (r.epm     != null) xml = _xlFillCell(xml, 'K' + row, r.epm,     true);  else xml = _xlWipe(xml, 'K' + row);
      if (r.carrera != null) xml = _xlFillCell(xml, 'L' + row, r.carrera, true);  else xml = _xlWipe(xml, 'L' + row);
      xml = _xlFillCell(xml, 'M' + row, r.obs || '', false);
    }
  }

  // ── FRAC TANK — limpiar primero las 15 filas (30-44) ──
  for (var i = 0; i < 15; i++) {
    var row = 30 + i;
    ['B','C','D','G','H','I','K','L','M'].forEach(function(c){ xml = _xlWipe(xml, c + row); });
  }

  // TURNO 1 — Niveles de Guardia → B/C/D (max 15)
  ft1.slice(0, 15).forEach(function(r, i) {
    var row = 30 + i;
    var d   = new Date(r.fecha);
    var h   = (d.getHours()<10?'0':'')+d.getHours()+':'+(d.getMinutes()<10?'0':'')+d.getMinutes();
    xml = _xlFillCell(xml, 'B' + row, 'C-' + r.pozo, false);
    xml = _xlFillCell(xml, 'C' + row, h,              false);
    xml = _xlFillCell(xml, 'D' + row, r.ctm || 0,    true);   // numérico (cm)
  });

  // TURNO 2 — Reporte Diario FT → G/H/I (max 15)
  ft2.slice(0, 15).forEach(function(r, i) {
    var row = 30 + i;
    var d   = new Date(r.fecha);
    var h   = (d.getHours()<10?'0':'')+d.getHours()+':'+(d.getMinutes()<10?'0':'')+d.getMinutes();
    xml = _xlFillCell(xml, 'G' + row, 'C-' + r.pozo, false);
    xml = _xlFillCell(xml, 'H' + row, h,              false);
    xml = _xlFillCell(xml, 'I' + row, r.ctm || 0,    true);   // numérico (cm)
  });

  return xml;
}

function descargarExcelNuevoFormato(recNombreCorto, fechaISO){
  if(typeof JSZip==='undefined'){showToast('⚠️ Cargando JSZip, intenta de nuevo');return;}
  var NOMBRES_COMPLETOS={'Manrique':'Manrique Jimenez P.','Cirilo':'Cirilo Cancino Gomez','Juan Carlos':'Juan Carlos Flores','Jose':'Jose Guadalupe Torres Garcia','Luis':'Luis Carlos Flores Cruz'};
  var recFull=NOMBRES_COMPLETOS[recNombreCorto]||recNombreCorto;
  var hist=getHistorial().filter(function(r){
    if(r.esAlarma)return false;
    var rr=r.recorredor||'';
    return rr===recNombreCorto||rr===recFull;
  });
  if(!hist.length){showToast('⚠️ Sin reportes de '+recFull);return;}
  var porFecha={};
  hist.forEach(function(r){
    var d=new Date(r.fecha).toLocaleDateString('es-MX',{day:'2-digit',month:'2-digit',year:'numeric'});
    if(!porFecha[d])porFecha[d]=[];
    porFecha[d].push(r);
  });
  var fechas=Object.keys(porFecha).sort(function(a,b){
    return new Date(a.split('/').reverse().join('-'))-new Date(b.split('/').reverse().join('-'));
  });
  if(fechaISO){
    var fd=new Date(fechaISO+'T12:00:00').toLocaleDateString('es-MX',{day:'2-digit',month:'2-digit',year:'numeric'});
    fechas=fechas.filter(function(f){return f===fd;});
    if(!fechas.length){showToast('⚠️ Sin reportes para esa fecha');return;}
  }
  var R_NS='http://schemas.openxmlformats.org/officeDocument/2006/relationships';
  JSZip.loadAsync(_b64ToUint8(_EXCEL_TPL_B64)).then(function(tz){
    return Promise.all([
      tz.file('xl/worksheets/sheet1.xml').async('string'),
      tz.file('xl/styles.xml').async('string'),
      tz.file('xl/workbook.xml').async('string'),
      tz.file('[Content_Types].xml').async('string'),
      tz.file('xl/worksheets/_rels/sheet1.xml.rels').async('string'),
      tz.file('_rels/.rels').async('string'),
    ]).then(function(parts){
      var sheetTpl=parts[0],stylesTpl=parts[1],wbXml=parts[2],ct=parts[3],srl=parts[4],rootRels=parts[5];
      // Agregar estilo 18 no-wrap
      var nxf='<xf numFmtId="0" fontId="7" fillId="0" borderId="1" xfId="0" applyFont="1" applyBorder="1" applyAlignment="1"><alignment horizontal="left" vertical="center" wrapText="0"/></xf>';
      if(stylesTpl.indexOf('wrapText="0"')<0){
        stylesTpl=stylesTpl.replace('</cellXfs>',nxf+'</cellXfs>');
        var cm=stylesTpl.match(/cellXfs count="(\d+)"/);
        if(cm)stylesTpl=stylesTpl.replace('count="'+cm[1]+'"','count="'+(parseInt(cm[1])+1)+'"');
      }
      // Sheets
      var sheets=fechas.map(function(fecha){
        var nombre=recFull.split(' ')[0]+' '+fecha.replace(/\//g,'-');
        return {name:nombre,xml:_buildSheet(sheetTpl,recFull,fecha,porFecha[fecha])};
      });
      var N=sheets.length;
      // workbook.xml
      var smatch=wbXml.match(/<sheets>[\s\S]*?<\/sheets>/);
      var ns='<sheets>'+sheets.map(function(s,i){return '<sheet xmlns:r="'+R_NS+'" name="'+s.name+'" sheetId="'+(i+1)+'" state="visible" r:id="rId'+(i+1)+'"/>';}).join('')+'</sheets>';
      wbXml=wbXml.replace(smatch[0],ns).replace(/<definedNames>[\s\S]*?<\/definedNames>/,'');
      // rels
      var wbRels='<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'+sheets.map(function(s,i){return '<Relationship Type="'+R_NS+'/worksheet" Target="/xl/worksheets/sheet'+(i+1)+'.xml" Id="rId'+(i+1)+'"/>';}).join('')+'<Relationship Type="'+R_NS+'/styles" Target="styles.xml" Id="rId'+(N+1)+'"/><Relationship Type="'+R_NS+'/theme" Target="theme/theme1.xml" Id="rId'+(N+2)+'"/></Relationships>';
      ct=ct.replace(/<Override PartName="\/xl\/worksheets\/sheet1\.xml"[^/]*\/>/,' ');
      ct=ct.replace('</Types>',sheets.map(function(s,i){return '<Override PartName="/xl/worksheets/sheet'+(i+1)+'.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>';}).join('')+'</Types>');
      var outZip=new JSZip();
      outZip.file('[Content_Types].xml',ct);
      outZip.file('_rels/.rels',rootRels);
      outZip.file('xl/workbook.xml',wbXml);
      outZip.file('xl/_rels/workbook.xml.rels',wbRels);
      outZip.file('xl/styles.xml',stylesTpl);
      var staticF=['xl/theme/theme1.xml','xl/drawings/drawing1.xml','xl/drawings/_rels/drawing1.xml.rels','xl/media/image1.png','docProps/core.xml','docProps/app.xml'];
      var sp=staticF.map(function(fn){return tz.file(fn).async('arraybuffer').then(function(d){outZip.file(fn,d);});});
      return Promise.all(sp).then(function(){
        sheets.forEach(function(s,i){
          outZip.file('xl/worksheets/sheet'+(i+1)+'.xml',s.xml);
          outZip.file('xl/worksheets/_rels/sheet'+(i+1)+'.xml.rels',srl);
        });
        return outZip.generateAsync({type:'blob',mimeType:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'});
      });
    });
  }).then(function(blob){
    var fn='Reporte_'+recFull.split(' ')[0]+'_'+new Date().toISOString().slice(0,10)+'.xlsx';
    var url=URL.createObjectURL(blob),a=document.createElement('a');
    a.href=url;a.download=fn;a.click();URL.revokeObjectURL(url);
    showToast('📥 '+fn+' ('+fechas.length+' día'+(fechas.length>1?'s':'')+')');
  }).catch(function(e){
    console.error('Excel error:',e);
    showToast('❌ Error: '+e.message);
  });
}

// ── _descargarTodosExcel ──────────────────────────────────────────────────
// Descarga un Excel por cada recorredor activo para la fecha indicada.
// Llamado desde el botón "📥 Reporte" en el panel de supervisión.
function _descargarTodosExcel(fechaISO){
  var recs = Object.keys(REC_MAP || {});
  if(!recs.length){ showToast('⚠️ Sin recorredores configurados'); return; }
  var delay = 0;
  recs.forEach(function(key){
    var nombre = (REC_MAP[key] && REC_MAP[key].nombre) ? REC_MAP[key].nombre : key;
    setTimeout(function(){
      descargarExcelNuevoFormato(nombre, fechaISO || null);
    }, delay);
    delay += 800;
  });
}
